import{_ as a,o as e,c as p,af as l}from"./chunks/framework.SW4JcFcZ.js";const n="/assets/cardputer_info.BR0gNoIn.jpg",b=JSON.parse('{"title":"新玩具 M5Stack 的 CardPuter 的折腾记录(一) —— 开发环境搭建篇","description":"","frontmatter":{"blogPost":true,"title":"新玩具 M5Stack 的 CardPuter 的折腾记录(一) —— 开发环境搭建篇","date":"2023-12-13T11:21:00.000Z","excerpt":"新玩具 M5Stack 的 CardPuter 的折腾记录(一) —— 开发环境搭建篇","tags":["嵌入式","开发套件","M5 Stack","CardPuter","乐鑫","esp32系列","esp32s3"],"categories":["开发套件"]},"headers":[],"relativePath":"blog/posts/新玩具M5STACK的CARDPUTER的折腾记录(一)_开发环境搭建篇.md","filePath":"blog/posts/新玩具M5STACK的CARDPUTER的折腾记录(一)_开发环境搭建篇.md","lastUpdated":1773908410000}'),o={name:"blog/posts/新玩具M5STACK的CARDPUTER的折腾记录(一)_开发环境搭建篇.md"};function t(c,s,r,i,d,u){return e(),p("div",null,[...s[0]||(s[0]=[l('<h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>最近一段时间特别迷恋有实体键盘的设备，所以入手了 M5 Stack 家的 CardPuter 开发套件</p><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>CardPuter 是 基于 esp32s3 的一款开发套件，有显示屏、键盘、麦克风、扬声器、实体键盘、红外发射器、TF 卡槽等外设，自带电池。</p><p><img src="'+n+`" alt="cardputer info"></p><h2 id="搭建-cardputer-开发环境" tabindex="-1">搭建 CardPuter 开发环境 <a class="header-anchor" href="#搭建-cardputer-开发环境" aria-label="Permalink to &quot;搭建 CardPuter 开发环境&quot;">​</a></h2><p>为 CardPuter 搭建 esp-idf 的开发环境<sup><a href="#note1">1</a></sup></p><h3 id="安装准备" tabindex="-1">安装准备 <a class="header-anchor" href="#安装准备" aria-label="Permalink to &quot;安装准备&quot;">​</a></h3><p>esp-idf 依赖以下系统软件包。请根据使用的 Linux 发行版本，选择合适的安装命令。</p><p>我是 ubuntu 系统，其他系统请参考官方文档</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#6F42C1;">sudo</span><span style="color:#032F62;"> apt-get</span><span style="color:#032F62;"> install</span><span style="color:#032F62;"> git</span><span style="color:#032F62;"> wget</span><span style="color:#032F62;"> flex</span><span style="color:#032F62;"> bison</span><span style="color:#032F62;"> gperf</span><span style="color:#032F62;"> python3</span><span style="color:#032F62;"> python3-pip</span><span style="color:#032F62;"> python3-venv</span><span style="color:#032F62;"> cmake</span><span style="color:#032F62;"> ninja-build</span><span style="color:#032F62;"> ccache</span><span style="color:#032F62;"> libffi-dev</span><span style="color:#032F62;"> libssl-dev</span><span style="color:#032F62;"> dfu-util</span><span style="color:#032F62;"> libusb-1.0-0</span></span></code></pre></div><h3 id="获取-esp-idf" tabindex="-1">获取 esp-idf <a class="header-anchor" href="#获取-esp-idf" aria-label="Permalink to &quot;获取 esp-idf&quot;">​</a></h3><p>打开终端，运行以下命令：</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#6F42C1;">mkdir</span><span style="color:#005CC5;"> -p</span><span style="color:#032F62;"> ~/esp</span></span>
<span class="line"><span style="color:#005CC5;">cd</span><span style="color:#032F62;"> ~/esp</span></span>
<span class="line"><span style="color:#6F42C1;">git</span><span style="color:#032F62;"> clone</span><span style="color:#005CC5;"> --recursive</span><span style="color:#032F62;"> https://github.com/espressif/esp-idf.git</span></span></code></pre></div><p>esp-idf 将下载至 ~/esp/esp-idf。</p><p>注意当前 CardPuter 的源码依赖 esp-idf 的版本是 v4.4.6</p><p>需要切换 esp-idf 的 git 分支到 v4.4.6</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#005CC5;">cd</span><span style="color:#032F62;"> ~/esp/esp-idf</span></span>
<span class="line"><span style="color:#6F42C1;">git</span><span style="color:#032F62;"> checkout</span><span style="color:#032F62;"> v4.4.6</span></span></code></pre></div><h3 id="使用-esp-idf-工具安装器安装依赖包" tabindex="-1">使用 esp-idf 工具安装器安装依赖包 <a class="header-anchor" href="#使用-esp-idf-工具安装器安装依赖包" aria-label="Permalink to &quot;使用 esp-idf 工具安装器安装依赖包&quot;">​</a></h3><p>运行 <code>install.sh</code></p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#005CC5;">cd</span><span style="color:#032F62;"> ~/esp/esp-idf</span></span>
<span class="line"><span style="color:#6F42C1;">./install.sh</span></span></code></pre></div><blockquote><p><strong>出现下载失败的现象的原因与解决办法</strong></p><p>原因：</p><p>esp-idf 工具安装器会下载 Github 发布版本中附带的一些工具，如果访问 Github 较为缓慢，可以设置一个环境变量，从而优先选择 Espressif 的下载服务器进行 Github 资源下载。</p><p>解决办法：</p><p>要在安装工具时优先选择 Espressif 下载服务器，请在运行 <code>install.sh</code> 时使用以下命令：</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#005CC5;">cd</span><span style="color:#032F62;"> ~/esp/esp-idf</span></span>
<span class="line"><span style="color:#D73A49;">export</span><span style="color:#24292E;"> IDF_GITHUB_ASSETS</span><span style="color:#D73A49;">=</span><span style="color:#032F62;">&quot;dl.espressif.com/github_assets&quot;</span></span>
<span class="line"><span style="color:#6F42C1;">./install.sh</span></span></code></pre></div></blockquote><p>运行 <code>export.sh</code> 设置环境变量</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#005CC5;">cd</span><span style="color:#032F62;"> ~/esp/esp-idf</span></span>
<span class="line"><span style="color:#6F42C1;">./export.sh</span></span></code></pre></div><p>出现这段文字就是设置 ESP 开发环境成功了</p><div class="language-term"><button title="Copy Code" class="copy"></button><span class="lang">term</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span>Done! You can now compile esp-idf projects.</span></span>
<span class="line"><span>Go to the project directory and run:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  idf.py build</span></span></code></pre></div><blockquote><p><strong>出现 <code>libusb-1.0.so.0</code> 找不到的问题的原因和解决办法</strong></p><p>我在设置环境变量遇到了如下的问题:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#6F42C1;">WARNING:</span><span style="color:#032F62;"> tool</span><span style="color:#032F62;"> openocd-esp32</span><span style="color:#032F62;"> version</span><span style="color:#032F62;"> v0.12.0-esp32-20230921</span><span style="color:#032F62;"> is</span><span style="color:#032F62;"> installed,</span><span style="color:#032F62;"> but</span><span style="color:#D73A49;"> &gt;</span><span style="color:#032F62;"> returned</span><span style="color:#032F62;"> non-zero</span><span style="color:#032F62;"> exit</span><span style="color:#032F62;"> code</span><span style="color:#24292E;"> (127) with error message:</span></span>
<span class="line"><span style="color:#6F42C1;">/home/zhaodi-chen/.espressif/tools/openocd-esp32/v0.12.0-esp32-20230921/</span><span style="color:#24292E;">&gt; </span><span style="color:#032F62;">openocd-esp32/bin/openocd:</span><span style="color:#032F62;"> error</span><span style="color:#032F62;"> while</span><span style="color:#032F62;"> loading</span><span style="color:#032F62;"> shared</span><span style="color:#032F62;"> libraries:</span><span style="color:#032F62;"> libusb-1.0.so</span><span style="color:#24292E;">.</span><span style="color:#D73A49;">&gt;</span><span style="color:#032F62;"> 0:</span><span style="color:#032F62;"> cannot</span><span style="color:#032F62;"> open</span><span style="color:#032F62;"> shared</span><span style="color:#032F62;"> object</span><span style="color:#032F62;"> file:</span><span style="color:#032F62;"> No</span><span style="color:#032F62;"> such</span><span style="color:#032F62;"> file</span><span style="color:#032F62;"> or</span><span style="color:#032F62;"> directory</span></span></code></pre></div><p>原因：</p><p>系统中没有安装 <code>libusb</code> 开发库, 其实是我忽略了安装 <code>esp-idf</code> 的系统依赖</p><p>解决办法：</p><p>ubuntu 系统可以使用下面的命令安装<code>libusb</code></p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#6F42C1;">sudo</span><span style="color:#032F62;"> apt</span><span style="color:#032F62;"> install</span><span style="color:#032F62;"> libusb-1.0-0-dev</span></span></code></pre></div></blockquote><h2 id="克隆-cardputer-的-demo-工程" tabindex="-1">克隆 CardPuter 的 Demo 工程 <a class="header-anchor" href="#克隆-cardputer-的-demo-工程" aria-label="Permalink to &quot;克隆 CardPuter 的 Demo 工程&quot;">​</a></h2><p>Demo 工程的页面： <a href="https://github.com/m5stack/M5Cardputer-UserDemo" target="_blank" rel="noreferrer">https://github.com/m5stack/M5Cardputer-UserDemo</a></p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#6F42C1;">git</span><span style="color:#032F62;"> clone</span><span style="color:#032F62;"> https://github.com/m5stack/M5Cardputer-UserDemo.git</span></span></code></pre></div><blockquote><p><strong>克隆总是失败解决办法</strong></p><p>如果克隆总是失败可以使用下面的加速链接下载源码包</p><div class="language-url"><button title="Copy Code" class="copy"></button><span class="lang">url</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span>https://cache.dadilive.top/main.zip?url=aHR0cHM6Ly9naXRodWIuY29tL201c3RhY2svTTVDYXJkcHV0ZXItVXNlckRlbW8vYXJjaGl2ZS9yZWZzL2hlYWRzL21haW4uemlw</span></span></code></pre></div></blockquote><h2 id="构建-cardputer-的-demo-工程" tabindex="-1">构建 CardPuter 的 Demo 工程 <a class="header-anchor" href="#构建-cardputer-的-demo-工程" aria-label="Permalink to &quot;构建 CardPuter 的 Demo 工程&quot;">​</a></h2><p>设置完 <code>esp-idf</code> 的环境变量。 进入 CardPuter 的 Demo 工程的目录，运行 <code>idf build</code></p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#005CC5;">cd</span><span style="color:#032F62;"> M5Cardputer-UserDemo</span></span>
<span class="line"><span style="color:#6F42C1;">idf</span><span style="color:#032F62;"> build</span></span></code></pre></div><p>终端出现下面的文字就代表编译成功了</p><div class="language-term"><button title="Copy Code" class="copy"></button><span class="lang">term</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span>Project build complete. To flash, run this command:</span></span>
<span class="line"><span>/home/zhaodi-chen/.espressif/python_env/idf4.4_py3.10_env/bin/python ../../esp/esp-idf/components/esptool_py/esptool/esptool.py -p (PORT) -b 460800 --before default_reset --after hard_reset --chip esp32s3  write_flash --flash_mode dio --flash_size detect --flash_freq 80m 0x0 build/bootloader/bootloader.bin 0x8000 build/partition_table/partition-table.bin 0x10000 build/cardputer.bin</span></span>
<span class="line"><span>or run &#39;idf.py -p (PORT) flash&#39;</span></span></code></pre></div><h2 id="注" tabindex="-1">注 <a class="header-anchor" href="#注" aria-label="Permalink to &quot;注&quot;">​</a></h2><div id="note1"></div> [1] CardPuter 使用了乐鑫的 esp32s3 soc 作为主控芯片，esp-idf 是乐鑫为 esp32 系列芯片提供的开发工具包。 <h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><p><a href="https://docs.espressif.com/projects/esp-idf/zh_CN/latest/esp32/get-started/linux-macos-setup.html#get-started-prerequisites" target="_blank" rel="noreferrer">Linux 和 macOS 平台工具链的标准设置</a></p>`,41)])])}const y=a(o,[["render",t]]);export{b as __pageData,y as default};
